import{_ as t,c as o,o as d,a3 as s}from"./chunks/framework.CTM16EAR.js";const h=JSON.parse('{"title":"Supabase 同步机制说明","description":"","frontmatter":{"search":false},"headers":[],"relativePath":"dev-log/sync-mechanism.md","filePath":"dev-log/sync-mechanism.md","lastUpdated":1774017776000}'),a={name:"dev-log/sync-mechanism.md"};function c(l,e,n,r,i,g){return d(),o("div",null,e[0]||(e[0]=[s('<h1 id="supabase-同步机制说明" tabindex="-1">Supabase 同步机制说明 <a class="header-anchor" href="#supabase-同步机制说明" aria-label="Permalink to &quot;Supabase 同步机制说明&quot;">​</a></h1><h2 id="_1-整体流程" tabindex="-1">1. 整体流程 <a class="header-anchor" href="#_1-整体流程" aria-label="Permalink to &quot;1. 整体流程&quot;">​</a></h2><ul><li><strong>触发</strong>：登录成功（含 INITIAL_SESSION / SIGNED_IN）→ <code>handleSignedInSession</code> → <code>initSyncLifecycle()</code> → <strong>先上传再下载</strong> 的 <code>syncAll()</code>。</li><li><strong>时间戳来源</strong>：<code>lastSyncTimestamp</code> 存在 <code>useSettingStore.settings.supabaseSync[0]</code>，下载时传入各 SyncService，用于增量查询（<code>last_modified &gt; lastSyncTimestamp</code>）；全量时传 <code>0</code>（如新设备/重置）。</li><li><strong>上传</strong>：各表只上传 <code>synced === false</code> 的本地项，upsert 后回填 <code>synced = true</code>、<code>cloudModified</code>。</li><li><strong>下载</strong>：按表从 Supabase 拉取（直接表查询或 RPC），再在本地做「时间戳/冲突」判断，决定是否写入或跳过（见下）。</li></ul><h2 id="_1-1-每次同步-先查库再在本地比对-问题出在「查库」这一步" tabindex="-1">1.1 每次同步：先查库再在本地比对（问题出在「查库」这一步） <a class="header-anchor" href="#_1-1-每次同步-先查库再在本地比对-问题出在「查库」这一步" aria-label="Permalink to &quot;1.1 每次同步：先查库再在本地比对（问题出在「查库」这一步）&quot;">​</a></h2><ul><li><strong>不是</strong>「先全量下载到内存再比对」：每一张表都是 <strong>先向数据库发查询</strong>（表 select 或 RPC），<strong>只拿到当前这一批行</strong>，再在客户端用这批行和本地内存里的数据做比对、合并。</li><li><strong>流程</strong>： <ol><li><strong>查库</strong>：对 activities/tasks/todos/… 分别发请求（带 <code>user_id</code> 和可选的 <code>last_modified &gt; lastSyncTimestamp</code>），拿到一批行（<strong>若 DB/PostgREST 有 1000 行上限，这里最多就 1000 行</strong>）。</li><li><strong>本地比对</strong>：用这批行的 id 在本地找对应项，按「云端删除 / 本地不存在则新增 / 本地存在则比时间戳决定是否覆盖」等规则合并。</li></ol></li><li><strong>结论</strong>：若某表超过 1000 行，且查库那一步被 1000 行限制截断，则<strong>没被查出来的行根本不会参与比对</strong>，所以会「少数据」。问题在 <strong>数据库查询阶段</strong>（返回行数被截断），不是「比对逻辑」写错。</li></ul><h2 id="_2-数据层-vs-应用层" tabindex="-1">2. 数据层 vs 应用层 <a class="header-anchor" href="#_2-数据层-vs-应用层" aria-label="Permalink to &quot;2. 数据层 vs 应用层&quot;">​</a></h2><ul><li><strong>数据层（云端是否缺失）</strong>：若某条 task/activity 从未被上传成功，则云端表里没有该行，下载再怎么做也不会出现。可能原因：上传前未把 <code>synced</code> 置为 false、上传失败未重试、或上传时机晚于下载（如登录后先下载再本地编辑未上传）。</li><li><strong>应用层（放行/时间戳比对）</strong>：云端有数据，但下载时被过滤掉。可能原因： <ul><li><strong>增量查询</strong>：<code>last_modified &gt; lastSyncTimestamp</code>，若 <code>lastSyncTimestamp</code> 被更新得比云端记录的 <code>last_modified</code> 还新，则该条不会被拉取。</li><li><strong>本地未同步保护</strong>：若本地已有同 id 且 <code>synced === false</code>，下载会跳过该条（避免覆盖未上传的本地修改）。</li><li><strong>时间戳比较</strong>：增量时若 <code>cloudTimestamp &lt;= localItem.cloudModified</code> 会跳过更新。</li></ul></li></ul><h2 id="_3-各实体下载入口" tabindex="-1">3. 各实体下载入口 <a class="header-anchor" href="#_3-各实体下载入口" aria-label="Permalink to &quot;3. 各实体下载入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>实体</th><th>下载方式</th><th>增量条件</th></tr></thead><tbody><tr><td>activities</td><td>BaseSyncService</td><td><code>last_modified &gt; lastSyncTimestamp</code></td></tr><tr><td>todos</td><td>RPC <code>get_full_todos</code></td><td>同上（RPC 内用 <code>p_last_modified</code>）</td></tr><tr><td>schedules</td><td>RPC <code>get_full_schedules</code></td><td>同上</td></tr><tr><td>tasks</td><td>RPC <code>get_full_tasks</code></td><td>同上</td></tr><tr><td>tags</td><td>BaseSyncService</td><td>同上</td></tr><tr><td>templates</td><td>BaseSyncService</td><td>同上</td></tr></tbody></table><h2 id="_4-关键指标-诊断用" tabindex="-1">4. 关键指标（诊断用） <a class="header-anchor" href="#_4-关键指标-诊断用" aria-label="Permalink to &quot;4. 关键指标（诊断用）&quot;">​</a></h2><ul><li><strong>lastSyncTimestamp</strong>：下载前/后的值；若下载后更新，则下次下载为增量。</li><li><strong>fetched</strong>：从 DB/RPC 拿到的行数。</li><li><strong>applied（downloaded）</strong>：通过时间戳/冲突判断后实际写入本地的条数。</li><li><strong>清除后本底</strong>：清除本地数据并重置 lastSyncTimestamp 后，本地列表应为空；再全量下载可验证「本底空 + 云端拉取数 = 写入数」。</li></ul><h2 id="_5-编辑后-debounce-上传-已实现" tabindex="-1">5. 编辑后 debounce 上传（已实现） <a class="header-anchor" href="#_5-编辑后-debounce-上传-已实现" aria-label="Permalink to &quot;5. 编辑后 debounce 上传（已实现）&quot;">​</a></h2><ul><li><strong>本地写入链</strong>（统一入口 <code>src/core/utils/scheduleDebouncedCloudUpload.ts</code>，再动态加载 <code>uploadAllDebounced</code>）： <ul><li><strong>批量</strong>：<code>saveAllDebounced()</code>（约 800ms）→ <code>saveAllNow</code> → <code>scheduleDebouncedCloudUpload()</code>。</li><li><strong>单实体</strong>：<code>updateTaskById</code> / <code>updateTodoById</code> / <code>updateActivityById</code> / <code>updateScheduleById</code> 等在 <code>save*</code> 成功后同样调用。</li><li><strong>Tag / Template</strong>：<code>useTagStore</code> / <code>useTemplateStore</code> 内对 <code>rawTags</code> / <code>rawTemplates</code> 的 <code>watch</code> → <code>saveTags</code> / <code>saveTemplates</code> 后调用同一函数。</li><li>以上均在约 <strong>5s</strong> 内合并为一次 <code>uploadAll()</code>（由 <code>autoSync.uploadAllDebounced</code> 实现）。</li></ul></li><li><strong>前置条件</strong>：<code>settings.autoSupabaseSync</code> 开启且已登录；否则 <code>uploadAllDebounced</code> 内部会直接返回。</li><li><strong>其它触发</strong>仍保留：失焦/切后台 <code>src/services/appCloseHandler.ts</code> 短防抖上传、回前台防抖下载/全量同步；<code>BaseSyncService.scheduleAutoUpload</code> 仍为表级可选能力，当前主路径不依赖它。</li></ul>',13)]))}const m=t(a,[["render",c]]);export{h as __pageData,m as default};
